/**
 * Convert a numeric index to lowercase alphabet
 */
function getAlphaIndex(num) {
  return String.fromCharCode(96 + num);
}

/**
 * Convert a numeric index to lowercase Roman numeral
 */
function getRomanIndex(num) {
  const romanMap = ["", "i", "ii", "iii", "iv", "v", "vi", "vii", "viii", "ix", "x"];
  return romanMap[num] || num.toString();
}

/**
 * Transform Jira Wiki-style headings into structured numbering
 */
function formatJiraWiki(text) {
  if (!text || typeof text !== 'string') return text || "";

  const lines = text.replace(/\\n/g, '\n').split('\n');

  let level1Counter = 0;
  let level2Counter = 0;
  let level3Counter = 0;

  const formattedLines = lines.map(line => {
    const trimmedLine = line.trim();

    if (trimmedLine.startsWith('####')) {
      return line.replace('####', '*');
    }

    if (trimmedLine.startsWith('###')) {
      level3Counter++;
      return line.replace('###', `${getRomanIndex(level3Counter)}.`);
    }

    if (trimmedLine.startsWith('##')) {
      level2Counter++;
      level3Counter = 0;
      return line.replace('##', `${getAlphaIndex(level2Counter)}.`);
    }

    if (trimmedLine.startsWith('#')) {
      level1Counter++;
      level2Counter = 0;
      level3Counter = 0;
      return line.replace('#', `${level1Counter}.`);
    }

    return line;
  });

  return formattedLines.join('\n');
}

function applyFullFormatting(text) {
  return formatJiraWiki(text);
}

