const config = $('Configure').first().json;

const token = $('Get Xray Token').first().json.token;

const GRAPHQL_URL = config.xray.graphqlUrl;

// Input
const projectId = $json.project_id;
const folderPath = ($json.xray_path || "").trim();

// ✅ EARLY RETURN: skip everything if empty
if (!folderPath) {
  return [
    {
      json: {
        count: null,
        existingTests: null,
        folderPath: null,
        projectId,
        skipped: true,
        reason: "xray_path is empty -> no API call executed",
      },
    },
  ];
}

// Pagination
let start = 0;
const limit = 100;
let total = 0;
const allTests = [];

// GraphQL query loop
do {
  const query = `
query {
  getTests(
    projectId: "${projectId}",
    folder: {
      path: "${folderPath}",
      includeDescendants: true
    },
    limit: ${limit},
    start: ${start}
  ) {
    total
    results {
      jira(fields: ["id", "key", "summary", "labels"])
      steps {
        action
        data
        result
        callTestIssueId
      }
    }
  }
}`;

  const res = await this.helpers.httpRequest({
    method: "POST",
    url: GRAPHQL_URL,
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: {
      query,
    },
    json: true,
  });

  const data = res?.data?.getTests;
  total = data?.total || 0;

  const results = data?.results || [];
  allTests.push(...results);

  start += limit;

} while (start < total);

// RETURN
return [
  {
    json: {
      projectId,
      folderPath,
      count: allTests.length,
      existingTests: allTests,
      skipped: false,
    },
  },
];

const data = $input.first().json;

// 1. Create a lookup map: Jira ID -> original array of steps
const testMap = {};
(data.existingTests || []).forEach(t => {
  if (t.jira && t.jira.id) {
    testMap[t.jira.id] = t.steps || [];
  }
});

// 2. Recursive function to resolve and flatten steps from callTestIssueId
function resolveSteps(steps, lookupMap, visited = new Set()) {
  let resolved = [];

  for (const step of steps) {
    if (step.callTestIssueId && lookupMap[step.callTestIssueId]) {
      const targetId = step.callTestIssueId;

      // Guard clause to prevent infinite loops if test cases reference each other circular-wise
      if (visited.has(targetId)) {
        continue; 
      }

      visited.add(targetId);
      // Recursively resolve nested referenced steps
      const subSteps = resolveSteps(lookupMap[targetId], lookupMap, new Set(visited));
      resolved = resolved.concat(subSteps);
      visited.delete(targetId);
    } else {
      // If it is a standard step, retain only the core content and exclude callTestIssueId
      resolved.push({
        action: step.action,
        data: step.data,
        result: step.result
      });
    }
  }

  return resolved;
}

// 3. Process data compression with flattened step resolution
const compressed = (data.existingTests || []).map(t => {
  const jiraData = t.jira || {};

  // Resolve all referenced steps for the current test case
  const fullSteps = resolveSteps(t.steps || [], testMap);

  return {
    id: jiraData.id,
    key: jiraData.key,
    summary: jiraData.summary,
    labels: jiraData.labels || [],
    sample_steps: fullSteps.slice(0, 15) // Slice the output to 15 steps to save tokens
  };
});

const result = {
  json: {
    ...data,
    existingTestsCompressed: compressed
  }
};

// Retain the original binary data from 'Input Form' node if available
try {
  const formNode = $('Input Form');
  if (formNode && formNode.item && formNode.item.binary) {
    result.binary = formNode.item.binary;
  }
} catch (e) {
  // Gracefully skip if 'Input Form' or binary object does not exist
}

return [result];

