function escapeForGraphQL(value) {
  if (value == null) return "";
  return String(value)
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"');
}

// =====================
// Build GraphQL steps (Fixed to prevent double-escaping inside arrays)
// =====================
function buildSteps(steps) {
  const formattedSteps = steps.map(step => {
    if (step.callTestIssueId) {
      return { callTestIssueId: String(step.callTestIssueId) };
    }
    if (step.callTestName) {
      return { callTestName: String(step.callTestName) };
    }
    // Return raw text here. Let JSON.stringify manage the primary escapes natively.
    return {
      action: step.action || "",
      data: step.data || "",
      result: step.result || ""
    };
  });

  const jsonString = JSON.stringify(formattedSteps, null, 2);
  return jsonString.replace(/"([^"]+)":/g, '$1:');
}

