const items = $input.all();

// =====================
// CONFIG
// =====================
const config = $('Configure').first().json;

//Get Xray credentials from Configure Node
const CLIENT_ID = config.xray.clientId;
const CLIENT_SECRET = config.xray.clientSecret;

const AUTH_URL = config.xray.authUrl;
const GRAPHQL_URL = config.xray.graphqlUrl;

//Get Jira credentials from Configure Node
const JIRA_BASE = config.jira.baseUrl;
const JIRA_EMAIL = config.jira.email;
const JIRA_API_TOKEN = config.jira.apiToken;

const ISSUE_LINK_URL = `${JIRA_BASE}/rest/api/3/issueLink`;
const JIRA_AUTH = "Basic " + Buffer.from(`${JIRA_EMAIL}:${JIRA_API_TOKEN}`).toString("base64");

// =====================
// XRAY AUTHENTICATION
// =====================
const auth = await this.helpers.httpRequest({
  method: "POST",
  url: AUTH_URL,
  body: { client_id: CLIENT_ID, client_secret: CLIENT_SECRET },
  json: true,
  headers: { "Content-Type": "application/json" },
});
const token = auth.replace(/"/g, "").trim();

// =====================
// HELPERS
// =====================
function extractCallTestNames(query) {
  if (!query) return [];
  // Safer regex to match callTestName regardless of whitespaces or newlines
  const matches = [...query.matchAll(/callTestName\s*:\s*"([^"]+)"/g)];
  return matches.map((m) => m[1]);
}

async function linkToOriginalTicket(testKey, originalTicketKey) {
  if (!testKey || !originalTicketKey) return;
  try {
    await this.helpers.httpRequest({
      method: "POST",
      url: ISSUE_LINK_URL,
      headers: {
        Authorization: JIRA_AUTH,
        "Content-Type": "application/json",
      },
      body: {
        type: { name: "Test" },
        inwardIssue: { key: testKey },
        outwardIssue: { key: originalTicketKey },
      },
      json: true,
    });
  } catch (err) {
    console.error(`Failed to link ticket ${testKey} to ${originalTicketKey}`, err);
  }
}

// =====================
// STATE & PRE-PROCESSING
// =====================
const callTestMap = {}; // Maps: summary/testTitle -> issueId OR jiraKey -> issueId
const results = [];

// 1. Process LINK_EXISTING_TEST items first (FIXED: Uses JQL query since existingIssueId is a Jira Key)
for (const item of items) {
  if (item.json.flowType !== "LINK_EXISTING_TEST") continue;

  const existingKey = item.json.existingIssueId; // e.g., "EP-19334"
  const originalTicketKey = item.json.originalTicketKey;
  const itemSummary = item.json.summary || item.json.testTitle; // Supports both naming variants flexibly

  try {
    // Querying by Key via JQL to get both the exact Key and the numeric system ID
    const res = await this.helpers.httpRequest({
      method: "POST",
      url: GRAPHQL_URL,
      headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
      body: { 
        query: `query { getTests(jql: "key = '${existingKey}'", limit: 1) { results { jira(fields: ["id", "key"]) } } }` 
      },
      json: true,
    });

    const testData = res?.data?.getTests?.results?.[0];
    const testKey = testData?.jira?.key;
    const testId = testData?.jira?.id;

    if (testKey && testId) {
      // Link the existing test case to the original epic/story ticket
      await linkToOriginalTicket(testKey, originalTicketKey);

      // Map both Key and Summary so subsequent dependent tests can dynamically resolve them
      callTestMap[testKey] = testId;
      if (itemSummary) callTestMap[itemSummary] = testId;

      results.push({
        success: true,
        type: "linked_existing_test",
        existingIssue: testKey,
        existingIssueId: testId,
        originalTicketKey,
      });
    } else {
      results.push({ success: false, error: `Jira Key '${existingKey}' not found via Xray JQL lookup`, item });
    }
  } catch (e) {
    results.push({ success: false, error: `Failed to process link: ${e.message}`, item });
  }
}

// 2. Pre-scan for existing dependencies in Jira via JQL
const allRequiredDependencies = new Set();
for (const item of items) {
  if (item.json.query) {
    extractCallTestNames(item.json.query).forEach(name => allRequiredDependencies.add(name));
  }
}

if (allRequiredDependencies.size > 0) {
  const names = [...allRequiredDependencies];
  const jql = `key in (${names.map((n) => `"${n}"`).join(",")}) or summary in (${names.map((n) => `"${n}"`).join(",")})`;

  try {
    const res = await this.helpers.httpRequest({
      method: "POST",
      url: GRAPHQL_URL,
      headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
      body: { query: `query { getTests(jql: "${jql}", limit: 100, start: 0) { results { jira(fields: ["id", "key", "summary"]) } } }` },
      json: true,
    });

    const tests = res?.data?.getTests?.results || [];
    for (const t of tests) {
      if (t?.jira?.id) {
        if (t.jira.key) callTestMap[t.jira.key] = t.jira.id;
        if (t.jira.summary) callTestMap[t.jira.summary] = t.jira.id;
      }
    }
  } catch (e) {
    // Suppress JQL errors
  }
}

// ==========================================
// DYNAMIC DEPENDENCY RESOLUTION (Queue Loop)
// ==========================================
let creationQueue = items.filter(item => item.json.query && item.json.flowType !== "LINK_EXISTING_TEST");
let attemptsWithoutProgress = 0;

while (creationQueue.length > 0) {
  const initialQueueLength = creationQueue.length;
  const skippedItems = [];

  for (const item of creationQueue) {
    let query = item.json.query;
    const originalTicketKey = item.json.originalTicketKey;
    const itemSummary = item.json.summary || item.json.testTitle; // Safeguard property mapping

    const dependencies = extractCallTestNames(query);

    // Verify if all dependencies for this test case are already created/resolved
    const allDepsResolved = dependencies.every(depName => !!callTestMap[depName]);

    if (!allDepsResolved) {
      skippedItems.push(item);
      continue; // Push unordered items to the next queue execution iteration loop
    }

    // Replace callTestName with the corresponding callTestIssueId
    query = query.replace(/callTestName\s*:\s*"([^"]+)"/g, (match, name) => {
      return `callTestIssueId: "${callTestMap[name]}"`;
    });

    try {
      // Execute the test creation request on Xray
      const res = await this.helpers.httpRequest({
        method: "POST",
        url: GRAPHQL_URL,
        headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
        body: { query: query }, 
        json: true,
      });

      const issueId = res?.data?.createTest?.test?.issueId;
      const key = res?.data?.createTest?.test?.jira?.key;

      if (issueId) {
        // Cache values into map for potential subsequent test dependencies
        if (itemSummary) callTestMap[itemSummary] = issueId;
        if (key) callTestMap[key] = issueId;

        // Link to the original ticket
        await linkToOriginalTicket(key, originalTicketKey);
        results.push({ success: true, key, issueId, originalTicketKey });
      } else {
        // Handle scenario where API returns 200 OK but encapsulates internal GraphQL error arrays
        const graphQLErrors = res?.errors ? JSON.stringify(res.errors) : "Unknown GraphQL Error";
        results.push({ success: false, error: graphQLErrors, item });
      }
    } catch (error) {
      results.push({ success: false, error: error.message, item });
    }
  }

  creationQueue = skippedItems;

  // Infinite loop protection mechanism (Circular Reference Guard)
  if (creationQueue.length === initialQueueLength) {
    attemptsWithoutProgress++;
    if (attemptsWithoutProgress > 1) {
      // Map unresolvable nodes cleanly instead of throwing unhandled exceptions
      creationQueue.forEach(i => {
        results.push({ success: false, error: "Unresolvable circular reference or missing dependency components", item: i });
      });
      break; 
    }
  } else {
    attemptsWithoutProgress = 0; 
  }
}

return results;

const config = $('Configure').first().json;

const auth = await this.helpers.httpRequest({
  method: "POST",
  url: config.xray.authUrl,
  body: {
    client_id: config.xray.clientId,
    client_secret: config.xray.clientSecret
  },
  json: false,
  headers: {
    "Content-Type": "application/json"
  }
});

return [{
  json: {
    token: auth.replace(/"/g, "").trim()
  }
}];

return [
{
  json: {
    xray: {
      clientId: "YOUR_XRAY_CLIENT_ID",
      clientSecret: "YOUR_XRAY_CLIENT_SECRET",
      authUrl: "https://xray.cloud.getxray.app/api/v2/authenticate",
      graphqlUrl: "https://xray.cloud.getxray.app/api/v2/graphql"
    },
    jira: {
      baseUrl: "https://your-company.atlassian.net",
      email: "your-email@example.com",
      apiToken: "YOUR_JIRA_API_TOKEN"
    }
  }
}
];
